import React, { useState, useRef, useEffect } from 'react'
import Quagga from 'quagga'
import ScannerTest from '../components/ScannerTest'
import ScanGuide from '../components/ScanGuide'
import './ScannerPage.css'

const ScannerPage = () => {
  const [isScanning, setIsScanning] = useState(false)
  const [scannedData, setScannedData] = useState('')
  const [scanHistory, setScanHistory] = useState([])
  const [cameraError, setCameraError] = useState('')
  const [deviceType, setDeviceType] = useState('desktop')
  const [scanResult, setScanResult] = useState(null)
  const [isChecking, setIsChecking] = useState(false)
  const scannerRef = useRef(null)

  // Configuration de Quagga pour la détection de codes-barres
  const quaggaConfig = {
    inputStream: {
      name: "Live",
      type: "LiveStream",
      target: scannerRef.current,
      constraints: {
        facingMode: "environment", // Utilise la caméra arrière sur mobile
        width: { min: 320, ideal: 640, max: 1920 },
        height: { min: 240, ideal: 480, max: 1080 },
        aspectRatio: { min: 1, max: 2 }
      }
    },
    locator: {
      patchSize: "medium",
      halfSample: true
    },
    numOfWorkers: 1, // Réduit à 1 pour Android
    frequency: 10,
    decoder: {
      readers: [
        "code_128_reader",
        "ean_reader",
        "ean_8_reader",
        "code_39_reader",
        "code_39_vin_reader",
        "codabar_reader",
        "upc_reader",
        "upc_e_reader",
        "i2of5_reader"
      ]
    },
    locate: true
  }

  // Vérifier les permissions Android
  const checkAndroidPermissions = async () => {
    if (deviceType === 'android') {
      try {
        // Vérifier si les permissions sont déjà accordées
        const permissions = await navigator.permissions.query({ name: 'camera' })
        if (permissions.state === 'denied') {
          setCameraError('Permissions caméra refusées sur Android. Allez dans Paramètres &gt; Applications &gt; Votre navigateur &gt; Permissions &gt; Caméra')
          return false
        }
        return true
      } catch (error) {
        console.log('Permissions API non supportée, continuation...')
        return true
      }
    }
    return true
  }

  // Vérifier la compatibilité du navigateur
  const checkBrowserCompatibility = () => {
    if (deviceType === 'android') {
      const userAgent = navigator.userAgent.toLowerCase()
      const isChrome = /chrome/.test(userAgent) && !/edge/.test(userAgent)
      const isFirefox = /firefox/.test(userAgent)
      const isSamsung = /samsungbrowser/.test(userAgent)
      
      if (!isChrome && !isFirefox && !isSamsung) {
        setCameraError('⚠️ Navigateur non supporté sur Android. Utilisez Chrome, Firefox ou Samsung Internet pour un meilleur support de la caméra.')
        return false
      }
      
      if (isChrome) {
        console.log('✅ Chrome détecté - Support optimal de la caméra')
      } else if (isFirefox) {
        console.log('✅ Firefox détecté - Support de la caméra')
      } else if (isSamsung) {
        console.log('✅ Samsung Internet détecté - Support de la caméra')
      }
    }
    return true
  }

  // Vérifier la compatibilité de l'API MediaDevices
  const checkMediaDevicesSupport = () => {
    // Support moderne
    if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
      return 'modern'
    }
    
    // Support legacy (anciens navigateurs)
    if (navigator.getUserMedia || navigator.webkitGetUserMedia || 
        navigator.mozGetUserMedia || navigator.msGetUserMedia) {
      return 'legacy'
    }
    
    return 'none'
  }

  // Polyfill pour les navigateurs anciens
  const getUserMediaLegacy = (constraints) => {
    return new Promise((resolve, reject) => {
      const getUserMedia = navigator.getUserMedia || 
                          navigator.webkitGetUserMedia || 
                          navigator.mozGetUserMedia || 
                          navigator.msGetUserMedia
      
      if (getUserMedia) {
        getUserMedia.call(navigator, constraints, resolve, reject)
      } else {
        reject(new Error('getUserMedia non supporté'))
      }
    })
  }

  // Démarrer le scan
  // Fonction pour vérifier le code-barres dans la base de données
  const checkBarcodeInDatabase = async (barcode) => {
    try {
      setIsChecking(true)
      const token = localStorage.getItem('authToken')
      
      if (!token) {
        setScanResult({
          found: false,
          message: 'Veuillez vous connecter pour vérifier les codes-barres',
          error: 'AUTH_REQUIRED'
        })
        return
      }

      // Récupérer tous les tickets pour vérifier le code-barres
      const response = await fetch('http://localhost:5000/api/tickets/', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      })

      if (response.ok) {
        const data = await response.json()
        if (data.success) {
          const tickets = data.data.tickets || []
          
          // Chercher le ticket avec ce code-barres
          const foundTicket = tickets.find(ticket => 
            ticket.barcode === barcode || 
            ticket.uuid === barcode ||
            ticket.visitor?.uuid === barcode
          )

          if (foundTicket) {
            // Ticket trouvé - afficher les informations
            setScanResult({
              found: true,
              ticket: foundTicket,
              message: '✅ Code-barres trouvé dans la base de données',
              visitor: foundTicket.visitor,
              status: foundTicket.status,
              circuit: foundTicket.visitor?.circuit || 'Non spécifié'
            })

            // Enregistrer le scan dans l'historique
            const newScan = {
              id: Date.now(),
              code: barcode,
              timestamp: new Date().toISOString(),
              device: deviceType,
              found: true,
              ticketInfo: foundTicket
            }
            setScanHistory(prev => [newScan, ...prev])

            // Enregistrer le scan dans la base de données
            await recordScanInDatabase(barcode, foundTicket.id, true)
          } else {
            // Code-barres non trouvé
            setScanResult({
              found: false,
              message: '❌ Code-barres non trouvé dans la base de données',
              error: 'NOT_FOUND'
            })

            // Enregistrer le scan dans l'historique
            const newScan = {
              id: Date.now(),
              code: barcode,
              timestamp: new Date().toISOString(),
              device: deviceType,
              found: false
            }
            setScanHistory(prev => [newScan, ...prev])

            // Enregistrer le scan dans la base de données
            await recordScanInDatabase(barcode, null, false)
          }
        } else {
          setScanResult({
            found: false,
            message: 'Erreur lors de la récupération des données',
            error: 'API_ERROR'
          })
        }
      } else {
        setScanResult({
          found: false,
          message: 'Erreur de connexion à la base de données',
          error: 'CONNECTION_ERROR'
        })
      }
    } catch (error) {
      console.error('Erreur lors de la vérification:', error)
      setScanResult({
        found: false,
        message: 'Erreur lors de la vérification du code-barres',
        error: 'UNKNOWN_ERROR'
      })
    } finally {
      setIsChecking(false)
    }
  }

  // Fonction pour enregistrer le scan dans la base de données
  const recordScanInDatabase = async (barcode, ticketId, found) => {
    try {
      const token = localStorage.getItem('authToken')
      if (!token) return

      const scanData = {
        barcode: barcode,
        ticket_id: ticketId,
        found: found,
        scan_time: new Date().toISOString(),
        device_type: deviceType,
        success: found
      }

      const response = await fetch('http://localhost:5000/api/scanner/scan', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(scanData)
      })

      if (response.ok) {
        console.log('Scan enregistré dans la base de données')
      }
    } catch (error) {
      console.error('Erreur lors de l\'enregistrement du scan:', error)
    }
  }

  const startScan = async () => {
    try {
      setCameraError('')
      setIsScanning(true)
      
      // Vérifier le support de l'API MediaDevices
      const mediaSupport = checkMediaDevicesSupport()
      
      if (mediaSupport === 'none') {
        setCameraError('🚫 Votre navigateur ne supporte pas l\'accès à la caméra. Utilisez Chrome, Firefox, Safari ou Edge récent.')
        setIsScanning(false)
        return
      }
      
      console.log(`Support MediaDevices: ${mediaSupport}`)

      // Vérifier les permissions Android
      const hasPermissions = await checkAndroidPermissions()
      if (!hasPermissions) {
        setIsScanning(false)
        return
      }

      // Vérifier la compatibilité du navigateur
      const isCompatible = checkBrowserCompatibility()
      if (!isCompatible) {
        setIsScanning(false)
        return
      }

      // Vérifier les permissions de caméra avec configuration adaptative
      let stream
      try {
        const videoConstraints = { 
          facingMode: 'environment',
          width: { min: 320, ideal: 640, max: 1920 },
          height: { min: 240, ideal: 480, max: 1080 },
          aspectRatio: { min: 1, max: 2 }
        }
        
        // Utiliser l'API appropriée selon le support
        if (mediaSupport === 'modern') {
          stream = await navigator.mediaDevices.getUserMedia({ video: videoConstraints })
        } else {
          stream = await getUserMediaLegacy({ video: videoConstraints })
        }
        console.log('Caméra arrière activée')
      } catch (error) {
        console.log('Caméra arrière non disponible, essai caméra avant:', error)
        try {
          const videoConstraints = { 
            facingMode: 'user',
            width: { min: 320, ideal: 640, max: 1920 },
            height: { min: 240, ideal: 480, max: 1080 },
            aspectRatio: { min: 1, max: 2 }
          }
          
          if (mediaSupport === 'modern') {
            stream = await navigator.mediaDevices.getUserMedia({ video: videoConstraints })
          } else {
            stream = await getUserMediaLegacy({ video: videoConstraints })
          }
          console.log('Caméra avant activée')
        } catch (secondError) {
          console.log('Caméra avant non disponible, essai caméra par défaut:', secondError)
          try {
            if (mediaSupport === 'modern') {
              stream = await navigator.mediaDevices.getUserMedia({ video: true })
            } else {
              stream = await getUserMediaLegacy({ video: true })
            }
            console.log('Caméra par défaut activée')
          } catch (finalError) {
            console.error('Aucune caméra disponible:', finalError)
            if (finalError.name === 'NotAllowedError') {
              setCameraError('Accès à la caméra refusé. Veuillez autoriser l\'accès à la caméra dans les paramètres de votre navigateur.')
            } else if (finalError.name === 'NotFoundError') {
              setCameraError('Aucune caméra trouvée sur votre appareil.')
            } else {
              setCameraError('Erreur d\'accès à la caméra: ' + finalError.message)
            }
            setIsScanning(false)
            return
          }
        }
      }
      
      // Arrêter le stream temporaire pour Quagga
      if (stream) {
        stream.getTracks().forEach(track => track.stop())
      }
      
      // Configuration Quagga ultra-optimisée pour la détection
      const optimizedConfig = {
        inputStream: {
          name: "Live",
          type: "LiveStream",
          target: scannerRef.current,
          constraints: deviceType === 'android' ? {
            facingMode: "environment",
            width: { min: 320, ideal: 640, max: 1280 }, // Réduire pour Android
            height: { min: 240, ideal: 480, max: 720 }
          } : {
            facingMode: "environment",
            width: { min: 640, ideal: 1280, max: 1920 },
            height: { min: 480, ideal: 720, max: 1080 },
            aspectRatio: { min: 1, max: 2 }
          }
        },
        locator: {
          patchSize: "small", // Réduire pour une détection plus précise
          halfSample: false // Désactiver pour améliorer la qualité
        },
        numOfWorkers: 1, // Réduire à 1 pour éviter les conflits
        frequency: 10, // Fréquence équilibrée
        decoder: {
          readers: [
            "code_128_reader",
            "code_39_reader",
            "code_39_vin_reader",
            "codabar_reader",
            "ean_reader",
            "ean_8_reader",
            "upc_reader",
            "upc_e_reader",
            "i2of5_reader"
          ]
        },
        locate: true,
        // Configuration de debug pour voir ce qui se passe
        debug: {
          drawBoundingBox: true,
          showFrequency: true,
          drawScanline: true,
          showPattern: true
        }
      }

      // Démarrer Quagga
      Quagga.init(optimizedConfig, (err) => {
        if (err) {
          console.error('Erreur d\'initialisation de Quagga:', err)
          let errorMessage = 'Erreur lors de l\'initialisation du scanner.'
          
          if (err.name === 'NotSupportedError') {
            if (deviceType === 'android') {
              errorMessage = '⚠️ Problème de compatibilité sur Android. Essayez de redémarrer votre navigateur ou utilisez Chrome/Firefox.'
            } else {
              errorMessage = 'Format de code-barres non supporté par votre navigateur.'
            }
          } else if (err.name === 'NotAllowedError') {
            if (deviceType === 'android') {
              errorMessage = '🚫 Accès à la caméra refusé sur Android. Vérifiez les permissions dans Paramètres &gt; Applications &gt; Votre navigateur &gt; Caméra'
            } else {
              errorMessage = 'Accès à la caméra refusé. Vérifiez les permissions.'
            }
          } else if (err.name === 'NotFoundError') {
            errorMessage = '📷 Aucune caméra trouvée sur votre appareil.'
          } else if (err.name === 'NotReadableError') {
            if (deviceType === 'android') {
              errorMessage = '⚠️ Caméra non accessible sur Android. Vérifiez qu\'aucune autre application n\'utilise la caméra.'
            } else {
              errorMessage = 'Impossible de lire le flux vidéo de la caméra.'
            }
          } else if (err.name === 'NotSupportedError') {
            errorMessage = '🌐 Votre navigateur ne supporte pas cette fonctionnalité. Utilisez Chrome ou Firefox.'
          }
          
          setCameraError(errorMessage)
          setIsScanning(false)
          return
        }
        
        console.log('Caméra initialisée avec succès')
        
        // Démarrer le scan
        Quagga.start()
        
        // Écouter les résultats de scan
        Quagga.onDetected((result) => {
          const code = result.codeResult.code
          console.log('🎯 Code détecté:', code)
          console.log('📊 Qualité de détection:', result.codeResult.confidence)
          console.log('🔍 Type de code:', result.codeResult.format)
          console.log('📏 Données complètes:', result)
          
          // Vérifier la qualité de la détection
          if (result.codeResult.confidence > 0.5) { // Réduire le seuil de confiance
            console.log('✅ Détection de qualité acceptable:', result.codeResult.confidence)
            
            // Arrêter temporairement le scan
            stopScan()
            
            // Vérifier le code-barres dans la base de données
            checkBarcodeInDatabase(code)
            
            // Mettre à jour les données scannées
            setScannedData(code)
            
            // Redémarrer après 3 secondes pour laisser le temps de voir le résultat
            setTimeout(() => {
              if (isScanning) {
                startScan()
              }
            }, 3000)
          } else {
            console.log('⚠️ Détection de faible qualité, ignorée:', result.codeResult.confidence)
            console.log('💡 Essayez de stabiliser l\'appareil ou d\'améliorer l\'éclairage')
          }
        })

        // Écouter les erreurs de Quagga
        Quagga.onProcessed((result) => {
          if (result) {
            console.log('📹 Frame traité:', result)
            if (result.codeResult && result.codeResult.code) {
              console.log('🔍 Code détecté dans le frame:', result.codeResult.code)
            }
          }
        })

        // Ajouter des logs pour le debug
        Quagga.onProcessed((result) => {
          if (result) {
            console.log('📹 Frame traité:', result)
            if (result.codeResult && result.codeResult.code) {
              console.log('🔍 Code détecté dans le frame:', result.codeResult.code)
            }
          }
        })

        // Logs de debug pour la configuration
        console.log('🔧 Configuration Quagga appliquée:', optimizedConfig)
        console.log('📱 Type d\'appareil détecté:', deviceType)
        console.log('🌐 Support navigateur:', checkMediaDevicesSupport())

      })

    } catch (error) {
      console.error('Erreur lors du démarrage du scan:', error)
      setCameraError('Erreur inattendue lors de l\'accès à la caméra: ' + error.message)
      setIsScanning(false)
    }
  }

  // Arrêter le scan
  const stopScan = () => {
    try {
      Quagga.stop()
      setIsScanning(false)
      console.log('Scan arrêté')
    } catch (error) {
      console.error('Erreur lors de l\'arrêt du scan:', error)
    }
  }

  // Fonction de test de détection
  const testDetection = () => {
    console.log('🧪 Test de détection démarré')
    console.log('📱 Type d\'appareil:', deviceType)
    console.log('🔧 Support navigateur:', checkMediaDevicesSupport())
    console.log('📷 État du scan:', isScanning)
    
    if (scannerRef.current) {
      console.log('✅ Référence scanner OK')
    } else {
      console.log('❌ Référence scanner manquante')
    }
    
    // Tester la configuration Quagga
    console.log('🔧 Configuration actuelle:', {
      deviceType,
      mediaSupport: checkMediaDevicesSupport(),
      isScanning,
      scannerRef: !!scannerRef.current
    })
  }

  // Détecter le type d'appareil et nettoyer lors du démontage du composant
  useEffect(() => {
    // Détecter le type d'appareil
    const detectDevice = () => {
      const userAgent = navigator.userAgent.toLowerCase()
      const isMobile = /android|webos|iphone|ipad|ipod|blackberry|iemobile|opera mini/i.test(userAgent)
      const isAndroid = /android/i.test(userAgent)
      const isIOS = /iphone|ipad|ipod/i.test(userAgent)
      
      if (isAndroid) {
        setDeviceType('android')
      } else if (isIOS) {
        setDeviceType('ios')
      } else if (isMobile) {
        setDeviceType('mobile')
      } else {
        setDeviceType('desktop')
      }
      
      console.log('Type d\'appareil détecté:', deviceType)
    }
    
    detectDevice()
    
    return () => {
      if (isScanning) {
        Quagga.stop()
      }
    }
  }, [isScanning])

  const handleManualInput = (e) => {
    setScannedData(e.target.value)
  }

  const handleManualScan = () => {
    if (scannedData.trim()) {
      // Vérifier le code-barres dans la base de données
      checkBarcodeInDatabase(scannedData.trim())
    }
  }

  const clearHistory = () => {
    setScanHistory([])
  }

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      handleManualScan()
    }
  }

  // Test de la caméra
  const testCamera = async () => {
    try {
      setCameraError('')
      let stream
      let cameraType = ''
      
      // Vérifier les permissions Android d'abord
      if (deviceType === 'android') {
        const hasPermissions = await checkAndroidPermissions()
        if (!hasPermissions) {
          return
        }
        
        // Vérifier la compatibilité du navigateur
        const isCompatible = checkBrowserCompatibility()
        if (!isCompatible) {
          return
        }
      }
      
      // Vérifier le support de l'API MediaDevices
      const mediaSupport = checkMediaDevicesSupport()
      if (mediaSupport === 'none') {
        setCameraError('🚫 Votre navigateur ne supporte pas l\'accès à la caméra. Utilisez Chrome, Firefox, Safari ou Edge récent.')
        return
      }
      
      // Essayer d'abord la caméra arrière (mobile)
      try {
        const videoConstraints = { 
          facingMode: 'environment',
          width: { min: 320, ideal: 640, max: 1920 },
          height: { min: 240, ideal: 480, max: 1080 }
        }
        
        if (mediaSupport === 'modern') {
          stream = await navigator.mediaDevices.getUserMedia({ video: videoConstraints })
        } else {
          stream = await getUserMediaLegacy({ video: videoConstraints })
        }
        cameraType = 'arrière (mobile)'
        console.log('Test caméra arrière réussi')
      } catch (error) {
        console.log('Caméra arrière non disponible, essai caméra avant:', error)
        
        // Essayer la caméra avant (PC)
        try {
          const videoConstraints = { 
            facingMode: 'user',
            width: { min: 320, ideal: 640, max: 1920 },
            height: { min: 240, ideal: 480, max: 1080 }
          }
          
          if (mediaSupport === 'modern') {
            stream = await navigator.mediaDevices.getUserMedia({ video: videoConstraints })
          } else {
            stream = await getUserMediaLegacy({ video: videoConstraints })
          }
          cameraType = 'avant (PC)'
          console.log('Test caméra avant réussi')
        } catch (secondError) {
          console.log('Caméra avant non disponible, essai caméra par défaut:', secondError)
          
          // Essayer la caméra par défaut
          try {
            if (mediaSupport === 'modern') {
              stream = await navigator.mediaDevices.getUserMedia({ video: true })
            } else {
              stream = await getUserMediaLegacy({ video: true })
            }
            cameraType = 'par défaut'
            console.log('Test caméra par défaut réussi')
          } catch (finalError) {
            throw finalError
          }
        }
      }
      
      if (stream) {
        // Afficher le stream dans un élément vidéo temporaire
        const video = document.createElement('video')
        video.srcObject = stream
        video.style.width = '100%'
        video.style.height = '100%'
        video.style.objectFit = 'cover'
        video.play()
        
        // Créer un conteneur pour le test
        const testContainer = document.createElement('div')
        testContainer.style.cssText = `
          position: fixed;
          top: 50%;
          left: 50%;
          transform: translate(-50%, -50%);
          width: 300px;
          height: 200px;
          background: #000;
          border-radius: 12px;
          overflow: hidden;
          z-index: 10000;
          box-shadow: 0 10px 30px rgba(0,0,0,0.5);
        `
        testContainer.appendChild(video)
        document.body.appendChild(testContainer)
        
        // Arrêter après 3 secondes
        setTimeout(() => {
          stream.getTracks().forEach(track => track.stop())
          document.body.removeChild(testContainer)
          setCameraError(`✅ Test de caméra ${cameraType} réussi ! La caméra fonctionne correctement.`)
          setTimeout(() => setCameraError(''), 4000)
        }, 3000)
      }
      
    } catch (error) {
      console.error('Erreur de test caméra:', error)
      if (error.name === 'NotAllowedError') {
        setCameraError('❌ Test échoué : Accès à la caméra refusé. Vérifiez les permissions.')
      } else if (error.name === 'NotFoundError') {
        setCameraError('❌ Test échoué : Aucune caméra trouvée.')
      } else {
        setCameraError('❌ Test échoué : ' + error.message)
      }
    }
  }

  return (
    <div className="scanner-page">
      <div className="scanner-hero">
        <h1>Scanner de Codes-Barres</h1>
        <p>Scannez les codes-barres des visiteurs pour vérifier leur validité</p>
      </div>

      {/* Composant de test pour démonstration */}
      <ScannerTest />
      
      {/* Guide de scan pour améliorer la précision */}
      <ScanGuide />

      <div className="scanner-container">
        <div className="scanner-section">
          <h2>Scanner de Codes-Barres</h2>
          
          <div className="scanner-controls">
            <button 
              className={`scan-button ${isScanning ? 'scanning' : ''}`}
              onClick={startScan}
              disabled={isScanning}
            >
              {isScanning ? '🔄 Scan en cours...' : '🎥 Démarrer le Scan'}
            </button>
            <button 
              className="stop-button" 
              onClick={stopScan}
              disabled={!isScanning}
            >
              ⏹️ Arrêter le Scan
            </button>
            <button 
              className="test-button" 
              onClick={testCamera}
              disabled={isScanning}
            >
              🧪 Tester la Caméra
            </button>
            <button 
              className="test-button" 
              onClick={testDetection}
              disabled={isScanning}
            >
              🔍 Test Détection
            </button>
          </div>
          
                     <div className="device-info">
             <span className="device-badge">
               📱 {deviceType === 'android' ? 'Android' : 
                    deviceType === 'ios' ? 'iOS' : 
                    deviceType === 'mobile' ? 'Mobile' : 'PC/Desktop'}
             </span>
             <span className="camera-tip">
               💡 {deviceType === 'android' ? 'Utilise la caméra arrière pour un meilleur scan. Assurez-vous d\'autoriser l\'accès à la caméra.' :
                    deviceType === 'ios' ? 'Utilise la caméra arrière pour un meilleur scan' :
                    deviceType === 'mobile' ? 'Utilise la caméra arrière pour un meilleur scan' : 'Utilise la caméra intégrée de votre PC'}
             </span>
             
             {/* Informations de diagnostic pour tous les appareils */}
             <div className="device-status">
               <p className="status-title">🔧 État de compatibilité :</p>
               <p className="status-api">API Caméra : {(() => {
                 const support = checkMediaDevicesSupport()
                 if (support === 'modern') return '✅ Moderne (navigateur récent)'
                 if (support === 'legacy') return '⚠️ Legacy (navigateur ancien)'
                 return '❌ Non supportée'
               })()}</p>
               <p className="status-browser">Navigateur : {navigator.userAgent.includes('Chrome') ? '✅ Chrome' : navigator.userAgent.includes('Firefox') ? '✅ Firefox' : navigator.userAgent.includes('Safari') ? '✅ Safari' : navigator.userAgent.includes('Edge') ? '✅ Edge' : navigator.userAgent.includes('Samsung') ? '✅ Samsung Internet' : '⚠️ Navigateur non optimisé'}</p>
             </div>
            {deviceType === 'android' && (
              <div className="android-tips">
                <p className="android-tip-title">🔧 Conseils pour Android :</p>
                <ul className="android-tip-list">
                  <li>• Utilisez Chrome ou Firefox (pas Internet Explorer)</li>
                  <li>• Autorisez l'accès à la caméra quand demandé</li>
                  <li>• Vérifiez les permissions dans Paramètres &gt; Applications</li>
                  <li>• Utilisez la caméra arrière pour de meilleurs résultats</li>
                  <li>• Fermez les autres applications qui utilisent la caméra</li>
                  <li>• Redémarrez le navigateur si la caméra ne répond pas</li>
                </ul>
                                 <div className="android-status">
                   <p className="status-title">📱 État de votre appareil :</p>
                   <p className="status-browser">Navigateur : {navigator.userAgent.includes('Chrome') ? '✅ Chrome' : navigator.userAgent.includes('Firefox') ? '✅ Firefox' : navigator.userAgent.includes('Samsung') ? '✅ Samsung Internet' : '⚠️ Navigateur non optimisé'}</p>
                   <p className="status-https">HTTPS : {window.location.protocol === 'https:' ? '✅ Sécurisé' : '⚠️ Local (OK pour les tests)'}</p>
                   <p className="status-api">API Caméra : {(() => {
                     const support = checkMediaDevicesSupport()
                     if (support === 'modern') return '✅ Moderne (navigateur récent)'
                     if (support === 'legacy') return '⚠️ Legacy (navigateur ancien)'
                     return '❌ Non supportée'
                   })()}</p>
                 </div>
              </div>
            )}
          </div>

          {cameraError && (
            <div className="camera-error">
              <span className="error-icon">⚠️</span>
              {cameraError}
            </div>
          )}

          <div className="scanner-preview">
            {isScanning ? (
              <div className="camera-active">
                <div ref={scannerRef} className="camera-viewport"></div>
                
                {/* Cadre de scan amélioré avec guide visuel */}
                <div className="scan-overlay">
                  <div className="scan-frame">
                    {/* Coins du cadre avec animation */}
                    <div className="scan-corners">
                      <div className="corner top-left"></div>
                      <div className="corner top-right"></div>
                      <div className="corner bottom-left"></div>
                      <div className="corner bottom-right"></div>
                    </div>
                    
                    {/* Ligne de scan animée */}
                    <div className="scan-line"></div>
                    
                    {/* Instructions de scan */}
                    <div className="scan-instructions">
                      <p className="instruction-main">📱 Placez le code-barres dans le cadre</p>
                      <p className="instruction-sub">🎯 Maintenez stable pour une meilleure détection</p>
                      <p className="instruction-tip">💡 Éclairage uniforme recommandé</p>
                    </div>
                    
                    {/* Zone de détection */}
                    <div className="detection-zone">
                      <div className="zone-indicator"></div>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="camera-placeholder">
                <span className="camera-icon">📷</span>
                <p>Cliquez sur "Démarrer le Scan" pour activer la caméra</p>
              </div>
            )}
          </div>
        </div>

        <div className="manual-input-section">
          <h2>Saisie Manuelle</h2>
          <div className="input-group">
            <input
              type="text"
              placeholder="Entrez le code-barres manuellement"
              value={scannedData}
              onChange={handleManualInput}
              onKeyPress={handleKeyPress}
              className="manual-input"
            />
            <button onClick={handleManualScan} className="scan-manual-button">
              🔍 Scanner
            </button>
          </div>
        </div>

        {/* Affichage du résultat du scan */}
        {scanResult && (
          <div className={`scan-result ${scanResult.found ? 'found' : 'not-found'}`}>
            <div className="result-header">
              <h3>Résultat de la Vérification</h3>
              <button 
                onClick={() => setScanResult(null)} 
                className="close-result-button"
              >
                ✕
              </button>
            </div>
            
            <div className="result-content">
              <div className="result-message">
                <span className="result-icon">
                  {scanResult.found ? '✅' : '❌'}
                </span>
                <p className="result-text">{scanResult.message}</p>
              </div>

              {scanResult.found && scanResult.ticket && (
                <div className="ticket-details">
                  <h4>Informations du Ticket</h4>
                  <div className="ticket-info-grid">
                    <div className="info-item">
                      <span className="info-label">UUID:</span>
                      <span className="info-value">{scanResult.ticket.uuid}</span>
                    </div>
                    <div className="info-item">
                      <span className="info-label">Statut:</span>
                      <span className={`status-badge ${scanResult.ticket.status}`}>
                        {scanResult.ticket.status === 'active' ? '🟢 Actif' : 
                         scanResult.ticket.status === 'used' ? '🔵 Utilisé' : 
                         scanResult.ticket.status === 'expired' ? '🟡 Expiré' : 
                         scanResult.ticket.status === 'cancelled' ? '🔴 Annulé' : 
                         scanResult.ticket.status}
                      </span>
                    </div>
                    {scanResult.visitor && (
                      <>
                        <div className="info-item">
                          <span className="info-label">Visiteur:</span>
                          <span className="info-value">
                            {scanResult.visitor.first_name} {scanResult.visitor.last_name}
                          </span>
                        </div>
                        <div className="info-item">
                          <span className="info-label">Email:</span>
                          <span className="info-value">{scanResult.visitor.email}</span>
                        </div>
                        <div className="info-item">
                          <span className="info-label">Pays:</span>
                          <span className="info-value">
                            {scanResult.visitor.country === 'MG' ? '🇲🇬 Madagascar' : 
                             scanResult.visitor.country === 'FR' ? '🇫🇷 France' : 
                             scanResult.visitor.country === 'US' ? '🇺🇸 États-Unis' : 
                             scanResult.visitor.country}
                          </span>
                        </div>
                        <div className="info-item">
                          <span className="info-label">Circuit:</span>
                          <span className="info-value">{scanResult.circuit}</span>
                        </div>
                      </>
                    )}
                  </div>
                </div>
              )}

              {!scanResult.found && (
                <div className="not-found-info">
                  <p>Ce code-barres n'est pas enregistré dans notre base de données.</p>
                  <p>Vérifiez que :</p>
                  <ul>
                    <li>Le code-barres a été correctement scanné</li>
                    <li>Le ticket a été créé dans le système</li>
                    <li>Le code-barres n'a pas expiré</li>
                  </ul>
                </div>
              )}
            </div>

            {isChecking && (
              <div className="checking-overlay">
                <div className="checking-spinner"></div>
                <p>Vérification en cours...</p>
              </div>
            )}
          </div>
        )}

        <div className="scan-results-section">
          <div className="results-header">
            <h2>Résultats du Scan</h2>
            <button onClick={clearHistory} className="clear-button">
              🗑️ Effacer l'historique
            </button>
          </div>
          
          {scanHistory.length === 0 ? (
            <div className="no-results">
              <p>Aucun scan effectué</p>
            </div>
          ) : (
            <div className="scan-history">
              {scanHistory.map((scan) => (
                <div key={scan.id} className={`scan-item ${scan.type}`}>
                  <div className="scan-data">
                    <strong>Code:</strong> {scan.data}
                    {scan.format && <span className="scan-format">({scan.format})</span>}
                  </div>
                  <div className="scan-info">
                    <span className="scan-time">{scan.timestamp}</span>
                    <span className={`scan-type ${scan.type}`}>
                      {scan.type === 'camera' ? '📷 Caméra' : '✏️ Manuel'}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

export default ScannerPage
